using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set AI:ApiKey in configuration or OPENAI_API_KEY environment variable.");

const string modelId = "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

builder.Services.AddSingleton<NoteService>();

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteService = host.Services.GetRequiredService<NoteService>();

// Define tools available to the agent
var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) =>
        {
            Console.WriteLine($"  🔍 Searching: {query}");
            return WebSearchTool.SearchAsync(query);
        },
        "web_search",
        "Searches the web for information on a topic. Returns a list of relevant snippets."),

    AIFunctionFactory.Create(
        ([Description("Title for the note")] string title,
         [Description("Content of the note")] string content) =>
        {
            Console.WriteLine($"  📝 Note saved: {title}");
            noteService.AddNote(title, content);
            return $"Note '{title}' saved successfully.";
        },
        "save_note",
        "Saves a research note with a title and content for later summarization."),

    AIFunctionFactory.Create(
        () =>
        {
            var notes = noteService.GetAllNotes();
            return notes.Count == 0
                ? "No notes saved yet."
                : string.Join("\n\n", notes.Select(n => $"## {n.Title}\n{n.Content}"));
        },
        "get_notes",
        "Retrieves all saved research notes."),
};

// Set up the agent
var agent = new ChatClientAgent(chatClient,
    "You are a research agent. Your job is to research a topic thoroughly by: " +
    "1) Searching the web for relevant information using multiple queries, " +
    "2) Saving important findings as notes, " +
    "3) Once you have gathered enough information (at least 3 notes), retrieve your notes and provide a comprehensive summary. " +
    "Be thorough but focused. Use different search queries to cover multiple angles of the topic.")
{
    Tools = tools,
};

// Get the research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

// Run the agent
string? finalResponse = null;
await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
    {
        finalResponse = message.Text;
    }
}

Console.WriteLine("\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");
Console.WriteLine(finalResponse ?? "No summary generated.");
Console.WriteLine();

// --- Supporting types ---

/// <summary>Simulates web search results for demonstration purposes.</summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new();

    public static async Task<string> SearchAsync(string query)
    {
        // In production, integrate with a real search API (Bing, Google, etc.)
        // This demonstrates the tool contract with a simulated response.
        await Task.Delay(100); // Simulate network latency

        return $"""
            Search results for: "{query}"

            1. [Wikipedia] {query} - Overview and background information covering key aspects of the topic.
               Summary: Provides foundational knowledge about {query}, including history, key concepts, and current state.

            2. [Research Paper] Recent advances in {query} - Academic perspective on latest developments.
               Summary: Covers cutting-edge research, methodologies, and findings related to {query}.

            3. [News Article] {query}: Current trends and future outlook - Industry analysis.
               Summary: Discusses market trends, expert opinions, and predictions about the future of {query}.

            4. [Technical Blog] Understanding {query} in practice - Practical applications and examples.
               Summary: Real-world use cases, implementation details, and lessons learned from applying {query}.
            """;
    }
}

/// <summary>Service for storing and retrieving research notes.</summary>
sealed class NoteService
{
    private readonly List<Note> _notes = [];

    public void AddNote(string title, string content) =>
        _notes.Add(new Note(title, content, DateTime.UtcNow));

    public IReadOnlyList<Note> GetAllNotes() => _notes.AsReadOnly();
}

record Note(string Title, string Content, DateTime CreatedAt);

