using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

const string modelId = "gpt-4o-mini-2024-07-18";

// Create the IChatClient via MEAI's OpenAI extension
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var noteService = new NoteService();

// Define tools available to the agent
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) =>
        {
            Console.WriteLine($"  🔍 Searching: \"{query}\"");
            return WebSearchTool.SearchAsync(query);
        },
        "web_search",
        "Searches the web for information on a topic. Returns relevant snippets."),

    AIFunctionFactory.Create(
        ([Description("Title for the note")] string title,
         [Description("Content of the note")] string content) =>
        {
            Console.WriteLine($"  📝 Note saved: \"{title}\"");
            noteService.AddNote(title, content);
            return $"Note '{title}' saved successfully.";
        },
        "save_note",
        "Saves a research note with a title and content for later summarization."),

    AIFunctionFactory.Create(
        () =>
        {
            var notes = noteService.GetAllNotes();
            Console.WriteLine($"  📖 Retrieved {notes.Count} note(s)");
            return notes.Count == 0
                ? "No notes saved yet."
                : string.Join("\n\n", notes.Select(n => $"## {n.Title}\n{n.Content}"));
        },
        "get_notes",
        "Retrieves all saved research notes."),
};

// Create the agent with tools and instructions
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly by:
        1) Searching the web for relevant information using multiple varied queries.
        2) Saving important findings as notes (save at least 3 notes covering different aspects).
        3) Once you have gathered enough information, retrieve your notes and provide a comprehensive summary.
        Be thorough but focused. Use different search queries to cover multiple angles.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools,
    loggerFactory: null,
    services: null);

// Get the research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

// Create a session and run the agent
var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session);

Console.WriteLine("\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");
Console.WriteLine(response.Text ?? "No summary generated.");

if (response.Usage is { } usage)
{
    Console.WriteLine($"\n📊 Tokens used — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}");
}

Console.WriteLine();

// --- Supporting types ---

/// <summary>Simulates web search results for demonstration purposes.</summary>
static class WebSearchTool
{
    public static async Task<string> SearchAsync(string query)
    {
        // In production, replace with a real search API (Bing Search, Google Custom Search, etc.)
        await Task.Delay(100); // Simulate network latency

        return $"""
            Search results for: "{query}"

            1. [Wikipedia] {query} — Overview and background information covering key aspects.
               Summary: Foundational knowledge about {query}, including history, key concepts, and current state.

            2. [Research Paper] Recent advances in {query} — Academic perspective on latest developments.
               Summary: Cutting-edge research, methodologies, and findings related to {query}.

            3. [News Article] {query}: Current trends and future outlook — Industry analysis.
               Summary: Market trends, expert opinions, and predictions about the future of {query}.

            4. [Technical Blog] Understanding {query} in practice — Practical applications.
               Summary: Real-world use cases, implementation details, and lessons learned.
            """;
    }
}

/// <summary>Service for storing and retrieving research notes.</summary>
sealed class NoteService
{
    private readonly List<Note> _notes = [];

    public void AddNote(string title, string content) =>
        _notes.Add(new Note(title, content, DateTime.UtcNow));

    public IReadOnlyList<Note> GetAllNotes() => _notes.AsReadOnly();
}

