IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var noteService = new NoteService();

// Define tools available to the agent
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) =>
        {
            Console.WriteLine($"  🔍 Searching: \"{query}\"");
            return WebSearchTool.SearchAsync(query);
        },
        "web_search",
        "Searches the web for information on a topic. Returns relevant snippets."),

    AIFunctionFactory.Create(
        ([Description("Title for the note")] string title,
         [Description("Content of the note")] string content) =>
        {
            Console.WriteLine($"  📝 Note saved: \"{title}\"");
            noteService.AddNote(title, content);
            return $"Note '{title}' saved successfully.";
        },
        "save_note",
        "Saves a research note with a title and content for later summarization."),

    AIFunctionFactory.Create(
        () =>
        {
            var notes = noteService.GetAllNotes();
            Console.WriteLine($"  📖 Retrieved {notes.Count} note(s)");
            return notes.Count == 0
                ? "No notes saved yet."
                : string.Join("\n\n", notes.Select(n => $"## {n.Title}\n{n.Content}"));
        },
        "get_notes",
        "Retrieves all saved research notes."),
};

